    cat << 'EOF' > /home/user/check_service.sh
#!/bin/bash
if [ -z "$1" ]; then
    echo "Usage: $0 <port>"
    exit 1
fi

if [ "$1" != "5522" ]; then
    echo "Error: Service not configured on port $1"
    exit 1
fi

echo -n "Enter Diagnostic PIN: "
read -r PIN

if [ "$PIN" == "7788" ]; then
    echo "Authentication successful."
    echo "Status: OK-DELAYED"
else
    echo "Authentication failed."
    echo "Status: UNAUTHORIZED"
    exit 1
fi
EOF

    chmod +x /home/user/check_service.sh
    chmod -R 777 /home/user